// Valida el JWT del header Authorization: Bearer <token>.
// Devuelve { valid: true, sub, role, exp } o { valid: false, reason }.
//
// Usado por:
//   - Frontend al montar la app (refresca/revoca sesión).
//   - Como guard interno de otros workflows admin (list-quotes, update-quote)
//     mediante un sub-workflow o copiando este bloque.
const jwt = require('jsonwebtoken');
const src = $input.first().json;
const auth = (src.headers && (src.headers.authorization || src.headers.Authorization)) || '';
const m = /^Bearer\s+(.+)$/i.exec(auth.trim());
if (!m) {
  return [{ json: { valid: false, reason: 'no_token' } }];
}
const token = m[1].trim();
const secret = $env.JWT_SECRET;
if (!secret) {
  return [{ json: { valid: false, reason: 'misconfigured' } }];
}
try {
  const payload = jwt.verify(token, secret, { issuer: 'solarhub', audience: 'admin' });
  return [{ json: { valid: true, sub: payload.sub, username: payload.username, role: payload.role, exp: payload.exp } }];
} catch (e) {
  return [{ json: { valid: false, reason: e?.name || 'verify_failed' } }];
}
